rss.channel:
{{ config.title }}
{{ config.base_url }}
{{ config.description }}

{%- for page in pages %}


    {{ page.title }}
    {{ page.permalink }}
    {{ page.date | date(format="%a, %d %b %Y %H:%M:%S %z") }}
    {{ config.author }}
    {{ page.permalink }}

      {{ page.content | replace(from='src="/', to='src="' ~ config.base_url ~ '/') | replace(from='href="/', to='href="' ~ config.base_url ~ '/') | safe }}
      <hr/>
      <p><i>You might be wondering how I know that you're awesome!</i><br/> Because I know you read this via RSS.</p>


{%- endfor %}
